query FulfillmentOrderPreconditionsStatusSearch($query: String!, $first: Int!) {
    fulfillmentOrders(first: $first, includeClosed: true, query: $query, sortKey: ID, reverse: true) {
      nodes {
        id
        status
        requestStatus
        order {
          id
          name
        }
      }
    }
  }

hydrate.query:
#graphql
  fragment FulfillmentOrderPreconditionFields on FulfillmentOrder {
    id
    status
    requestStatus
    fulfillAt
    fulfillBy
    updatedAt
    supportedActions {
      action
    }
    assignedLocation {
      name
      location {
        id
        name
      }
    }
    fulfillmentHolds {
      id
      handle
      reason
      reasonNotes
      displayReason
      heldByRequestingApp
    }
    lineItems(first: 20) {
      nodes {
        id
        totalQuantity
        remainingQuantity
        lineItem {
          id
          title
          quantity
          fulfillableQuantity
        }
      }
    }
    order {
      id
      name
      displayFulfillmentStatus
    }
  }

  query FulfillmentOrderPreconditionsRead($id: ID!) {
    fulfillmentOrder(id: $id) {
      ...FulfillmentOrderPreconditionFields
    }
  }

